// Tag browser renderer using shared libraries
// Uses tag_tree_builder and tag_picker_ui libraries

export async function render(browser, api) {
  // Load shared libraries
  const treeBuilder = await api.require('tag_tree_builder');
  const tagPickerUI = await api.require('tag_picker_ui');

  const container = api.createElement('div', {
    class: 'tag-browser-view',
    style: 'max-width: 600px; margin: 0 auto;'
  }, []);

  // Header
  const header = api.createElement('div', {
    style: 'margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #e0e0e0;'
  }, []);

  const title = api.createElement('h2', {
    style: 'margin: 0; font-size: 20px;'
  }, [browser.name || 'Tag Browser']);
  header.appendChild(title);

  container.appendChild(header);

  // Get all tag items and build tree
  const TAG_TYPE_ID = "d1da8525-b0dc-4a79-8bef-0cbed1ed003d";
  const tags = await api.query({ type: TAG_TYPE_ID });
  const tree = treeBuilder.buildTagTree(tags);

  // Track expanded state (tag ID -> boolean)
  const expandedState = new Map();

  // Results container (for showing matched items)
  const resultsContainer = api.createElement('div', {
    style: 'margin-top: 20px; padding: 15px; background: #f9f9f9; border-radius: 6px; display: none;'
  }, []);

  const resultsTitle = api.createElement('h3', {
    style: 'margin: 0 0 15px 0; font-size: 16px; color: #333;'
  }, []);
  resultsContainer.appendChild(resultsTitle);

  const resultsList = api.createElement('div', {
    style: 'max-height: 400px; overflow-y: auto;'
  }, []);
  resultsContainer.appendChild(resultsList);

  // Tag tree container
  const treeContainer = api.createElement('div', {
    style: 'display: flex; flex-direction: column;'
  }, []);

  // Function to show items tagged with a specific tag
  const showTaggedItems = async (tag) => {
    console.log('Clicked tag:', tag);

    // Find all items with this tag
    const allItems = await api.getAll();
    const taggedItems = allItems.filter(item =>
      item.tags && item.tags.includes(tag.id)
    );

    console.log('Found tagged items:', taggedItems);

    // Update results title
    const tagName = treeBuilder.getTagName(tag);
    resultsTitle.textContent = 'Items tagged with "' + tagName + '" (' + taggedItems.length + ')';

    // Clear and populate results list
    resultsList.innerHTML = '';

    if (taggedItems.length === 0) {
      const emptyMsg = api.createElement('div', {
        style: 'padding: 20px; text-align: center; color: #999; font-style: italic;'
      }, ['No items found with this tag.']);
      resultsList.appendChild(emptyMsg);
    } else {
      taggedItems.forEach(item => {
        const itemDiv = api.createElement('div', {
          style: 'padding: 12px; margin-bottom: 8px; background: white; border: 1px solid #ddd; border-radius: 4px; cursor: pointer; transition: background 0.2s;'
        }, []);

        const itemName = api.createElement('div', {
          style: 'font-weight: 500; color: #333; margin-bottom: 4px;'
        }, [item.name || item.content?.title || item.id]);
        itemDiv.appendChild(itemName);

        const itemMeta = api.createElement('div', {
          style: 'font-size: 12px; color: #999;'
        }, ['Type: ' + item.type.substring(0, 8) + '... | Modified: ' + new Date(item.modified).toLocaleDateString()]);
        itemDiv.appendChild(itemMeta);

        itemDiv.onclick = () => {
          api.openSibling(item.id);
        };

        itemDiv.onmouseover = () => { itemDiv.style.background = '#f0f0f0'; };
        itemDiv.onmouseout = () => { itemDiv.style.background = 'white'; };

        resultsList.appendChild(itemDiv);
      });
    }

    // Show results container
    resultsContainer.style.display = 'block';
  };

  // Function to render the entire tree
  const renderTree = () => {
    tagPickerUI.renderTagBrowser({
      container: treeContainer,
      tree: tree,
      expandedState: expandedState,
      onClick: showTaggedItems,
      onExpand: () => renderTree()
    }, api);
  };

  // Initial render
  renderTree();

  container.appendChild(treeContainer);
  container.appendChild(resultsContainer);

  return container;
}

// kernel-storage module
export class Storage {
  constructor() {
    this.db = null;
    this.dbName = "hobson";
    this.storeName = "items";
  }

  async initialize() {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.dbName, 2);

      request.onerror = () => reject(new Error("Failed to open database"));

      request.onsuccess = (event) => {
        this.db = event.target.result;
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = event.target.result;

        if (!db.objectStoreNames.contains(this.storeName)) {
          const store = db.createObjectStore(this.storeName, { keyPath: "id" });
          store.createIndex("type", "type", { unique: false });
          store.createIndex("modified", "modified", { unique: false });
          store.createIndex("name", "name", { unique: false });
        }
      };
    });
  }

  async get(id) {
    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readonly");
      const store = transaction.objectStore(this.storeName);
      const request = store.get(id);

      request.onerror = () => reject(new Error(`Failed to get item: ${id}`));
      request.onsuccess = () => {
        if (request.result) {
          resolve(request.result);
        } else {
          reject(new Error(`Item not found: ${id}`));
        }
      };
    });
  }

  async set(item, kernel) {
    // Validation before saving
    await this._validateItem(item, kernel);

    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readwrite");
      const store = transaction.objectStore(this.storeName);
      const request = store.put(item);

      request.onerror = () => reject(new Error(`Failed to save item: ${item.id}`));
      request.onsuccess = () => resolve();
    });
  }

  async delete(id) {
    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readwrite");
      const store = transaction.objectStore(this.storeName);
      const request = store.delete(id);

      request.onerror = () => reject(new Error(`Failed to delete item: ${id}`));
      request.onsuccess = () => resolve();
    });
  }

  async query(filter) {
    const all = await this.getAll();
    return all.filter(item => {
      for (const [key, value] of Object.entries(filter)) {
        if (item[key] !== value) return false;
      }
      return true;
    });
  }

  async getAll() {
    return new Promise((resolve, reject) => {
      const transaction = this.db.transaction([this.storeName], "readonly");
      const store = transaction.objectStore(this.storeName);
      const request = store.getAll();

      request.onerror = () => reject(new Error("Failed to get all items"));
      request.onsuccess = () => resolve(request.result || []);
    });
  }

  async exists(id) {
    try {
      await this.get(id);
      return true;
    } catch {
      return false;
    }
  }

  async _validateItem(item, kernel) {
    const IDS = {
      ATOM: "00000000-0000-0000-0000-000000000000",
      TYPE_DEFINITION: "00000000-0000-0000-0000-000000000001",
      CODE: "00000000-0000-0000-0000-000000000002"
    };

    // 1. Validate type chain (must reach atom, no cycles)
    await this._validateTypeChain(item.type, new Set(), IDS.ATOM);

    // 2. If code item, validate name uniqueness
    if (kernel && await kernel.isCodeItem(item)) {
      if (!item.name) {
        throw new Error(`Code item ${item.id} must have a name`);
      }

      const existing = await this.query({ name: item.name });
      const conflict = existing.find(i => i.id !== item.id);
      if (conflict) {
        throw new Error(`Code item named '${item.name}' already exists (id: ${conflict.id})`);
      }
    }
  }

  async _validateTypeChain(typeId, visited, ATOM_ID) {
    if (visited.has(typeId)) {
      throw new Error(`Circular type chain detected at: ${typeId}`);
    }

    visited.add(typeId);

    // Self-referential atom is valid
    if (typeId === ATOM_ID) {
      return;
    }

    try {
      const typeItem = await this.get(typeId);
      await this._validateTypeChain(typeItem.type, visited, ATOM_ID);
    } catch (error) {
      if (error.message.includes("not found")) {
        throw new Error(`Type chain broken - item '${typeId}' not found`);
      }
      throw error;
    }
  }
}

// code_editor_renderer
// Type: renderer
// For Type: code (00000000-0000-0000-0000-000000000002)
// Purpose: Provides a comfortable editing experience for all code items

export async function render(item, api) {
  const container = api.createElement('div', { class: 'code-editor-view' }, []);

  // Header with item name and type
  const header = api.createElement('div', { 
    style: 'margin-bottom: 15px; padding-bottom: 10px; border-bottom: 2px solid #e0e0e0;' 
  }, []);

  const title = api.createElement('h3', { style: 'margin: 0; display: inline-block;' }, [
    item.name || item.id
  ]);
  header.appendChild(title);

  const typ = await api.get(item.type);
  const typeInfo = api.createElement('span', { 
    style: 'margin-left: 15px; color: #666; font-size: 13px;' 
  }, [`Type: ${typ.name}`]);
  header.appendChild(typeInfo);

  container.appendChild(header);

  // Code textarea with better styling
  const textarea = api.createElement('textarea', {
    style: `
      width: 100%;
      min-height: 500px;
      font-family: 'SF Mono', Monaco, Menlo, 'Courier New', monospace;
      font-size: 13px;
      line-height: 1.6;
      padding: 15px;
      border: 1px solid #d0d0d0;
      border-radius: 6px;
      background: #fafafa;
      resize: vertical;
      tab-size: 2;
      -moz-tab-size: 2;
    `,
    spellcheck: false,
    autocomplete: 'off',
    autocorrect: 'off',
    autocapitalize: 'off'
  }, []);

  textarea.value = item.content?.code || '';

  // Tab key handling for indentation
  textarea.addEventListener('keydown', (e) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      textarea.value = textarea.value.substring(0, start) + '  ' + textarea.value.substring(end);
      textarea.selectionStart = textarea.selectionEnd = start + 2;
    }
  });

  // Auto-save indicator
  const saveIndicator = api.createElement('span', { 
    style: 'margin-left: 10px; color: #999; font-size: 12px;' 
  }, ['']);

  textarea.addEventListener('input', () => {
    saveIndicator.textContent = 'Unsaved changes...';
    saveIndicator.style.color = '#cc6600';
  });

  container.appendChild(textarea);

  // Button bar
  const buttonBar = api.createElement('div', { 
    style: 'margin-top: 15px; display: flex; gap: 10px; align-items: center;' 
  }, []);

  const saveBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer; font-size: 14px; font-weight: 500;',
    onclick: async () => {
      saveBtn.disabled = true;
      saveBtn.textContent = 'Saving...';

      try {
        const updated = {
          ...item,
          content: {
            ...item.content,
            code: textarea.value
          }
        };
        await api.update(updated);

        saveIndicator.textContent = 'Saved!';
        saveIndicator.style.color = '#00aa00';
        saveBtn.textContent = 'Save';

        setTimeout(() => {
          saveIndicator.textContent = '';
        }, 2000);
      } catch (error) {
        alert(`Error saving: ${error.message}`);
        saveBtn.textContent = 'Save';
      } finally {
        saveBtn.disabled = false;
      }
    }
  }, ['Save']);
  buttonBar.appendChild(saveBtn);

  const saveAndTestBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer; font-size: 14px;',
    onclick: async () => {
      saveAndTestBtn.disabled = true;
      saveAndTestBtn.textContent = 'Saving...';

      try {
        const updated = {
          ...item,
          content: {
            ...item.content,
            code: textarea.value
          }
        };
        await api.update(updated);

        // For renderers, refresh by navigating away and back
        const currentRoot = api.getCurrentRoot();
        if (currentRoot === item.id) {
          // Viewing this code item directly - refresh it
          await api.navigate(api.IDS.WORKSPACE);
          setTimeout(() => api.navigate(item.id), 50);
        } else {
          // Viewing something else that uses this code - refresh that
          await api.navigate(api.IDS.WORKSPACE);
          setTimeout(() => api.navigate(currentRoot), 50);
        }
      } catch (error) {
        alert(`Error: ${error.message}`);
        saveAndTestBtn.textContent = 'Save & Test';
        saveAndTestBtn.disabled = false;
      }
    }
  }, ['Save & Test']);
  buttonBar.appendChild(saveAndTestBtn);

  buttonBar.appendChild(saveIndicator);

  // Keyboard shortcuts hint
  const hint = api.createElement('span', { 
    style: 'margin-left: auto; color: #999; font-size: 12px;' 
  }, ['Tip: Use Tab for indentation']);
  buttonBar.appendChild(hint);

  container.appendChild(buttonBar);

  return container;
}

// kernel-module-system module
export class ModuleSystem {
  constructor(kernel) {
    console.log("ModuleSystem");
    this.kernel = kernel;
    this.moduleCache = new Map(); // itemId -> { module, timestamp }
  }

  async require(nameOrId, callStack = new Set()) {
    // Resolve name to ID if necessary
    let itemId = nameOrId;

    // Check if it's a name (not a UUID pattern)
    if (!nameOrId.includes("-") || nameOrId.length < 36) {
      const items = await this.kernel.storage.query({ name: nameOrId });
      if (items.length === 0) {
        throw new Error(`Code item not found: ${nameOrId}`);
      }
      itemId = items[0].id;
    }

    // Check for circular dependencies
    if (callStack.has(itemId)) {
      const chain = Array.from(callStack).join(" -> ");
      throw new Error(`Circular dependency detected: ${chain} -> ${itemId}`);
    }

    // Check cache
    const cached = this.moduleCache.get(itemId);
    const item = await this.kernel.storage.get(itemId);

    // Validate cache freshness
    if (cached && cached.timestamp >= item.modified) {
      return cached.module;
    }

    // Re-evaluate
    callStack.add(itemId);
    const module = await this.evaluateCodeItem(item, callStack);
    callStack.delete(itemId);

    // Update cache
    this.moduleCache.set(itemId, {
      module,
      timestamp: item.modified
    });

    return module;
  }

  async evaluateCodeItem(item) {
    if (!item.content?.code) {
      throw new Error(`Item ${item.id} has no code to evaluate`);
    }

    const code = `
      "use strict";
      ${item.content.code}
      //# sourceURL=${item.name || `${item.id}.js`}
    `;

    const blob = new Blob([code], { type: "application/javascript" });
    const url = URL.createObjectURL(blob);

    try {
      const module = await import(url);
      return module;
    } catch (error) {
      throw new Error(`Failed to evaluate code item ${item.id} (${item.name}): ${error.message}`);
    } finally {
      URL.revokeObjectURL(url);
    }
  }

  async isCodeItem(item) {
    const CODE_ID = "00000000-0000-0000-0000-000000000002";
    return await this.typeChainIncludes(item.type, CODE_ID);
  }

  async typeChainIncludes(typeId, targetId) {
    const ATOM_ID = "00000000-0000-0000-0000-000000000000";
    let current = typeId;
    const visited = new Set();

    while (current && !visited.has(current)) {
      if (current === targetId) return true;
      visited.add(current);

      if (current === ATOM_ID) break;

      try {
        const typeItem = await this.kernel.storage.get(current);
        current = typeItem.type;
      } catch {
        break;
      }
    }

    return false;
  }

  clearCache() {
    this.moduleCache.clear();
  }
}
