          renderBody();
        }
      }, ['Edit']);
      bodyContainer.appendChild(editBtn);

      await renderTags(false);
    }
  };

  await renderBody();
  container.appendChild(bodyContainer);

  return container;
}

/**
 * Search items based on query string
 */
export async function searchItems(query, api, options = {}) {
  if (!query || query.trim().length === 0) {
    return [];
  }

  const { targetContainer, allItems } = options;
  let itemsToSearch;

  if (allItems) {
    itemsToSearch = allItems;
  } else if (targetContainer) {
    try {
      const container = await api.get(targetContainer);
      const childIds = (container.children || []).map(c =>
        typeof c === 'string' ? c : c.id
      );
      itemsToSearch = await Promise.all(
        childIds.map(id => api.get(id).catch(() => null))
      );
      itemsToSearch = itemsToSearch.filter(i => i !== null);
    } catch (err) {
      console.error('Error fetching container:', err);
      itemsToSearch = [];
    }
  } else {
    itemsToSearch = await api.getAll();
  }

  const queryLower = query.toLowerCase();
  const matches = itemsToSearch.filter(item => {
    const searchableText = [
      item.name,
      item.content?.title,
      item.content?.body,
      item.content?.description,
      JSON.stringify(item.content)
    ].filter(Boolean).join(' ').toLowerCase();

    return searchableText.includes(queryLower);
  });

  matches.sort((a, b) => a.name.localeCompare(b.name));
  return matches;
}

/**
 * Create a search UI widget
 */
export function createSearchUI(containerEl, onSelect, api, options = {}) {
  const {
    placeholder = 'Search for items...',
    savedQuery = '',
    targetContainer = null,
    autoFocus = false
  } = options;

  containerEl.innerHTML = '';

  const searchBox = api.createElement('div', {
    style: 'margin-bottom: 20px;'
  }, []);

  const input = api.createElement('input', {
    type: 'text',
    placeholder,
    value: savedQuery,
    style: 'width: 100%; padding: 12px 16px; font-size: 16px; border: 2px solid #d0d0d0; border-radius: 8px; outline: none; transition: border-color 0.2s;'
  }, []);

  input.onfocus = () => { input.style.borderColor = '#3b82f6'; };
  input.onblur = () => { input.style.borderColor = '#d0d0d0'; };

  searchBox.appendChild(input);
  containerEl.appendChild(searchBox);

  const resultsContainer = api.createElement('div', {}, []);
  containerEl.appendChild(resultsContainer);

  const statusDiv = api.createElement('div', {
    style: 'padding: 40px; text-align: center; color: #999; font-style: italic;'
  }, ['Type to search...']);
  resultsContainer.appendChild(statusDiv);

  const resultsList = api.createElement('div', {
    style: 'display: none; max-height: 600px; overflow-y: auto;'
  }, []);
  resultsContainer.appendChild(resultsList);

  let searchTimeout = null;
  let currentQuery = savedQuery;

  const executeSearch = async (query) => {
    currentQuery = query;

    if (!query || query.trim().length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.textContent = 'Type to search...';
      return;
    }

    statusDiv.style.display = 'block';
    resultsList.style.display = 'none';
    statusDiv.textContent = 'Searching...';

    const matches = await searchItems(query, api, { targetContainer });

    if (matches.length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.innerHTML = '';

      // Message
      const noMatchMsg = api.createElement('div', {
        style: 'margin-bottom: 16px;'
      }, ['No items found matching "' + query + '"']);
      statusDiv.appendChild(noMatchMsg);

      // Create New button
      const createBtn = api.createElement('button', {
        style: 'padding: 10px 20px; background: #3b82f6; color: white; border: none; border-radius: 6px; cursor: pointer; font-size: 14px; font-weight: 500; transition: background 0.2s;',
        onclick: async () => {
          try {
            // Look up note type
            const noteTypes = await api.query({ name: 'note' });
            const noteTypeId = noteTypes[0]?.id || '871ae771-b9b1-4f40-8c7f-d9038bfb69c3';

            // Create sanitized name (lowercase, underscores for spaces)
            const sanitizedName = query.toLowerCase().replace(/\s+/g, '_');

            // Create new note item
            const newItem = {
              id: crypto.randomUUID(),
              name: sanitizedName,
              type: noteTypeId,
              created: Date.now(),
              modified: Date.now(),
              children: [],
              content: {
                title: query,
                description: ''
              }
            };

            // Save and select
            await api.set(newItem);
            onSelect(newItem);
          } catch (err) {
            console.error('Failed to create item:', err);
            alert('Failed to create item: ' + err.message);
          }
        }
      }, ['Create New: ' + query]);

      // Hover effects
      createBtn.onmouseover = () => {
        createBtn.style.background = '#2563eb';
      };
      createBtn.onmouseout = () => {
        createBtn.style.background = '#3b82f6';
      };

      statusDiv.appendChild(createBtn);
    } else {
      statusDiv.style.display = 'none';
      resultsList.style.display = 'block';
      resultsList.innerHTML = '';

      const countHeader = api.createElement('div', {
        style: 'margin-bottom: 15px; font-size: 14px; color: #666; font-weight: 500;'
      }, ['Found ' + matches.length + ' item' + (matches.length === 1 ? '' : 's')]);
      resultsList.appendChild(countHeader);

      matches.forEach(item => {
        const resultDiv = api.createElement('div', {
          style: 'padding: 12px; margin-bottom: 8px; background: white; border: 1px solid #ddd; border-radius: 6px; cursor: pointer; transition: all 0.2s;'
        }, []);

        const itemTitle = api.createElement('div', {
          style: 'font-weight: 500; color: #333; margin-bottom: 6px; font-size: 15px;'
        }, [item.name || item.content?.title || item.id]);
        resultDiv.appendChild(itemTitle);

        const previewText = item.content?.body || item.content?.description ||
                           JSON.stringify(item.content).substring(0, 150);
        const preview = api.createElement('div', {
          style: 'font-size: 13px; color: #666; margin-bottom: 6px; line-height: 1.4; overflow: hidden; text-overflow: ellipsis; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical;'
        }, [previewText.substring(0, 200)]);
        resultDiv.appendChild(preview);

        const meta = api.createElement('div', {
          style: 'font-size: 12px; color: #999;'
        }, [
          'Type: ' + item.type.substring(0, 8) + '... | Modified: ' +
          new Date(item.modified).toLocaleDateString()
        ]);
        resultDiv.appendChild(meta);

        resultDiv.onclick = () => { onSelect(item); };

        resultDiv.onmouseover = () => {
          resultDiv.style.background = '#f8f9fa';
          resultDiv.style.borderColor = '#3b82f6';
          resultDiv.style.transform = 'translateX(4px)';
        };
        resultDiv.onmouseout = () => {
          resultDiv.style.background = 'white';
          resultDiv.style.borderColor = '#ddd';
          resultDiv.style.transform = 'translateX(0)';
        };

        resultsList.appendChild(resultDiv);
      });
    }
  };

  const performSearch = (query) => {
    if (searchTimeout) {
      clearTimeout(searchTimeout);
    }
    searchTimeout = setTimeout(() => {
      executeSearch(query);
    }, 300);
  };

  input.oninput = (e) => {
    performSearch(e.target.value);
  };

  if (autoFocus) {
    setTimeout(() => input.focus(), 0);
  }

  if (savedQuery && savedQuery.trim().length > 0) {
    executeSearch(savedQuery);
  }

  return {
    performSearch: executeSearch,
    getQuery: () => currentQuery,
    setQuery: (query) => {
      input.value = query;
      executeSearch(query);
    },
    destroy: () => {
      if (searchTimeout) {
        clearTimeout(searchTimeout);
      }
      containerEl.innerHTML = '';
    }
  };
}

export async function render(item, api) {
  const container = api.createElement('div', {
    style: 'display: flex; flex-direction: column; gap: 16px; min-width: 500px;'
  }, []);

  // JSON textarea
  const textarea = api.createElement('textarea', {
    style: 'width: 100%; height: 400px; font-family: monospace; font-size: 13px; padding: 12px; border: 1px solid #ccc; border-radius: 4px; resize: vertical;',
    spellcheck: 'false'
  }, []);
  textarea.value = JSON.stringify(item, null, 2);
  container.appendChild(textarea);

  // Error message area
  const errorArea = api.createElement('div', {
    style: 'color: #c00; font-size: 13px; min-height: 20px;'
  }, []);
  container.appendChild(errorArea);

  // Button row
  const buttonRow = api.createElement('div', {
    style: 'display: flex; gap: 10px; justify-content: flex-end;'
  }, []);

  // Cancel button
  const cancelBtn = api.createElement('button', {
    style: 'padding: 8px 16px; cursor: pointer;',
    onclick: () => api.close()
  }, ['Cancel']);
  buttonRow.appendChild(cancelBtn);

  // Save button
  const saveBtn = api.createElement('button', {
    style: 'padding: 8px 16px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px;',
    onclick: async () => {
      try {
        const parsed = JSON.parse(textarea.value);
        // Preserve the original ID - prevent accidental ID changes
        parsed.id = item.id;
        await api.saveAndClose(parsed);
      } catch (e) {
        errorArea.textContent = 'Invalid JSON: ' + e.message;
      }
    }
  }, ['Save']);
  buttonRow.appendChild(saveBtn);

  container.appendChild(buttonRow);

  // Keyboard shortcut: Ctrl/Cmd+S to save
  textarea.addEventListener('keydown', async (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 's') {
      e.preventDefault();
      try {
        const parsed = JSON.parse(textarea.value);
        parsed.id = item.id;
        await api.saveAndClose(parsed);
      } catch (err) {
        errorArea.textContent = 'Invalid JSON: ' + err.message;
      }
    }
  });

  return container;
}

// kernel-rendering module
export class RenderingSystem {
  constructor(kernel) {
    this.kernel = kernel;
  }

  async renderItem(itemId, rendererId = null) {
    const IDS = this.kernel.IDS;
    const item = await this.kernel.storage.get(itemId);

    // Use specified renderer or find default for item's type
    let renderer;
    if (rendererId) {
      renderer = await this.kernel.storage.get(rendererId);
    } else {
      renderer = await this.findRenderer(item.type);
    }

    // Load and execute renderer
    try {
      const rendererModule = await this.kernel.moduleSystem.require(renderer.id);
      const api = this.createRendererAPI(item);
      const domNode = await rendererModule.render(item, api);
      return domNode;
    } catch (error) {
      return this.createErrorView(error, itemId);
    }
  }

  async findRenderer(typeId) {
    const IDS = this.kernel.IDS;
    let currentType = typeId;
    const visited = new Set();

    while (currentType && !visited.has(currentType)) {
      visited.add(currentType);

      // Look for a renderer for this type
      const renderers = await this.kernel.storage.query({ type: IDS.RENDERER });
      const renderer = renderers.find(r => r.content?.for_type === currentType);

      if (renderer) {
        return renderer;
      }

      // Move up the type chain
      if (currentType === IDS.ATOM) {
        break;
      }

      try {
        const typeItem = await this.kernel.storage.get(currentType);
        currentType = typeItem.type;
      } catch {
        break;
      }
    }

    // Fall back to default renderer
    return await this.kernel.storage.get(IDS.DEFAULT_RENDERER);
  }

  // Get all renderers for a type (including inherited from type chain)
  async getRenderers(typeId) {
    const IDS = this.kernel.IDS;
    const allRenderers = await this.kernel.storage.query({ type: IDS.RENDERER });
    const result = [];
    const seenTypes = new Set();

    let currentType = typeId;
    const visited = new Set();

    while (currentType && !visited.has(currentType)) {
      visited.add(currentType);

      // Find all renderers for this type
      const renderersForType = allRenderers.filter(r => r.content?.for_type === currentType);
      for (const renderer of renderersForType) {
        if (!seenTypes.has(renderer.id)) {
          seenTypes.add(renderer.id);
          result.push({
            renderer,
            forType: currentType,
            inherited: currentType !== typeId
          });
        }
      }

      // Move up the type chain
      if (currentType === IDS.ATOM) {
        break;
      }

      try {
        const typeItem = await this.kernel.storage.get(currentType);
        currentType = typeItem.type;
      } catch {
        break;
      }
    }

    // Always include default renderer as fallback option
    const defaultRenderer = await this.kernel.storage.get(IDS.DEFAULT_RENDERER);
    if (!seenTypes.has(defaultRenderer.id)) {
      result.push({
        renderer: defaultRenderer,
        forType: IDS.ATOM,
        inherited: true,
        isDefault: true
      });
    }

    return result;
  }

  // Get the default renderer for a type
  async getDefaultRenderer(typeId) {
    const renderers = await this.getRenderers(typeId);
    return renderers.length > 0 ? renderers[0].renderer : null;
  }

  createRendererAPI(containerItem) {
    const kernel = this.kernel;
    const IDS = kernel.IDS;

    const api = {
      // Create DOM elements
      createElement(tag, props = {}, children = []) {
        const element = document.createElement(tag);

        for (const [key, value] of Object.entries(props)) {
          if (key.startsWith("on") && typeof value === "function") {
            const eventName = key.substring(2).toLowerCase();
            element.addEventListener(eventName, value);
          } else if (key === "class") {
            element.className = value;
          } else if (key === "style" && typeof value === "string") {
            element.style.cssText = value;
          } else {
            element.setAttribute(key, value);
          }
        }

        for (const child of children) {
          if (typeof child === "string") {
            element.appendChild(document.createTextNode(child));
          } else if (child instanceof Node) {
            element.appendChild(child);
          } else if (Array.isArray(child)) {
            // Handle array shorthand: [tag, props, children]
            const [childTag, childProps = {}, childChildren = []] = child;
            const childElement = api.createElement(childTag, childProps, childChildren);
            element.appendChild(childElement);
          }
        }

        return element;
      },

      // Query items (read-only)
      query: (filter) => kernel.storage.query(filter),

      // Get single item (read-only)
      get: (itemId) => kernel.storage.get(itemId),

      // Get all items
      getAll: () => kernel.storage.getAll(),

      // Load code module
      require: (nameOrId) => kernel.moduleSystem.require(nameOrId),

      // Render another item (for containers)
      renderItem: (itemId, rendererId) => kernel.rendering.renderItem(itemId, rendererId),

      // Renderer discovery
      getRenderers: (typeId) => kernel.rendering.getRenderers(typeId),
      getDefaultRenderer: (typeId) => kernel.rendering.getDefaultRenderer(typeId),
      findRenderer: (typeId) => kernel.rendering.findRenderer(typeId),

      // Editors
      getEditors: (typeId) => kernel.getEditors(typeId),
      getDefaultEditor: (typeId) => kernel.getDefaultEditor(typeId),
      editItem: (itemId, editorId) => kernel.editItem(itemId, editorId),
      getEditingContext: () => kernel._editingContext,

      // Navigation
      navigate: (itemId) => kernel.navigateToItem(itemId),
      getCurrentRoot: () => kernel.currentRoot,

      // Open item as sibling window in current container
      openSibling: async (itemId) => {
        const currentRoot = kernel.currentRoot;
        if (!currentRoot) {
          throw new Error('No current root container');
        }
        await kernel.addChild(currentRoot, itemId);
        // Trigger re-render to show the new child
        await kernel.renderRoot(currentRoot);
      },

      // Create new item
      create: async (item, addAsChild = false) => {
        const newItem = {
          ...item,
          id: item.id || crypto.randomUUID(),
          created: Date.now(),
          modified: Date.now(),
          children: item.children || []
        };

        await kernel.storage.set(newItem, kernel);

        if (addAsChild) {
          await kernel.addChild(containerItem.id, newItem.id);
        }

        return newItem.id;
      },

      // Simplified child creation
      createChild: async (type, content = {}) => {
        const newItem = {
          type,
          content,
          children: []
        };
        const id = await api.create(newItem, true);
        // Trigger re-render to show the new child (re-render the root, not necessarily this container)
        await kernel.renderRoot(kernel.currentRoot);
        return id;
      },

      // Save without triggering re-render
      set: async (item) => {
        const updated = {
          ...item,
          modified: Date.now()
        };
        await kernel.storage.set(updated, kernel);
        return item.id;
      },

      // Save and trigger re-render
      update: async (item) => {
        const updated = {
          ...item,
          modified: Date.now()
        };
        await kernel.storage.set(updated, kernel);
        await kernel.renderRoot(kernel.currentRoot);
        return item.id;
      },

      // Deprecated: use set() instead
      updateSilent: async (item) => {
        const updated = {
          ...item,
          modified: Date.now()
        };
        await kernel.storage.set(updated, kernel);
        return item.id;
      },

      // Add child to current container
      addChild: async (childId) => {
        await kernel.addChild(containerItem.id, childId);
      },

      // Remove child from current container
      removeChild: async (childId) => {
        await kernel.removeChild(containerItem.id, childId);
      },

      // Set renderer for a child in current container (2 params)
      // or in any container (3 params: parentId, childId, rendererId)
      setChildRenderer: async (childIdOrParentId, rendererIdOrChildId, optionalRendererId) => {
        if (optionalRendererId !== undefined) {
          // 3-parameter version: setChildRenderer(parentId, childId, rendererId)
          await kernel.setChildRenderer(childIdOrParentId, rendererIdOrChildId, optionalRendererId);
        } else {
          // 2-parameter version: setChildRenderer(childId, rendererId)
          await kernel.setChildRenderer(containerItem.id, childIdOrParentId, rendererIdOrChildId);
        }
      },

      // Find parent of an item
      findParentOf: (itemId) => kernel.findParentOf(itemId),

      // Delete item entirely
      delete: async (itemId) => {
        await kernel.deleteItem(itemId);
      },

      // Get the current container item
      getCurrentItem: () => containerItem,

      // Type chain utilities
      typeChainIncludes: (typeId, targetId) => kernel.moduleSystem.typeChainIncludes(typeId, targetId),

      // UI operations
      editRaw: (itemId) => kernel.editItemRaw(itemId),
      showItemList: () => kernel.showItemList(),

      // For script execution - returns REPL API for code evaluation
      createREPLContext: () => kernel.createREPLAPI(),

      // Well-known IDs
      IDS,

      // Helper functions (same as REPL API)
      helpers: {
        findByName: async (name) => {
          const items = await kernel.storage.query({ name });
          return items.length > 0 ? items[0] : null;
        },
        listByType: async (typeId) => {
          return await kernel.storage.query({ type: typeId });
        },
        createType: async (name, description) => {
          const IDS = kernel.IDS;
          const id = crypto.randomUUID();
          await kernel.storage.set({
            id,
            name,
            type: IDS.TYPE_DEFINITION,
            created: Date.now(),
            modified: Date.now(),
            children: [],
            content: { description }
          }, kernel);
          return id;
        }
      },

      // Viewport API for view state management
      viewport: {
        select: (itemId, parentId) => kernel.viewport.select(itemId, parentId),
        clearSelection: () => kernel.viewport.clearSelection(),
        getSelection: () => kernel.viewport.getSelection(),
        getSelectionParent: () => kernel.viewport.getSelectionParent(),
        getRoot: () => kernel.viewport.rootId,
        getRootRenderer: () => kernel.viewport.getRootRenderer(),
        setRootRenderer: async (rendererId) => {
          kernel.viewport.setRootRenderer(rendererId);
          await kernel.viewport.persist();
        }
      }
    };

    return api;
  }

  createErrorView(error, itemId) {
    const container = document.createElement("div");
    container.className = "render-error";

    const heading = document.createElement("h3");
    heading.textContent = `Error rendering: ${itemId}`;
    container.appendChild(heading);

    const message = document.createElement("pre");
    message.textContent = error.message;
    container.appendChild(message);

    const stack = document.createElement("pre");
    stack.textContent = error.stack || "(no stack trace)";
    container.appendChild(stack);

    const editBtn = document.createElement("button");
    editBtn.textContent = "Edit Item";
    editBtn.onclick = () => this.kernel.editItemRaw(itemId);
    container.appendChild(editBtn);

    return container;
  }
}

