// Tag Tree Builder Library
// Shared logic for building hierarchical tag trees

/**
 * Builds a hierarchical tree structure from a flat list of tag items
 * @param {Array} tags - Flat array of tag items
 * @returns {Array} Root nodes of the tree, each with a children array
 */
export function buildTagTree(tags) {
  // Create map of tags by ID for quick lookup
  const tagMap = new Map();
  tags.forEach(tag => tagMap.set(tag.id, { ...tag, children: [] }));

  // Separate root and child tags
  const roots = [];
  tags.forEach(tag => {
    const parent = tag.content.parent;
    if (!parent) {
      // Root tag (no parent)
      roots.push(tagMap.get(tag.id));
    } else {
      // Child tag - add to parent's children array
      const parentNode = tagMap.get(parent);
      if (parentNode) {
        parentNode.children.push(tagMap.get(tag.id));
      } else {
        // Parent not found - treat as root
        roots.push(tagMap.get(tag.id));
      }
    }
  });

  // Sort all nodes by name (case-insensitive)
  const sortByName = (a, b) => {
    const nameA = (a.content.name || a.name || a.id).toLowerCase();
    const nameB = (b.content.name || b.name || b.id).toLowerCase();
    return nameA.localeCompare(nameB);
  };

  roots.sort(sortByName);
  tagMap.forEach(node => node.children.sort(sortByName));

  return roots;
}

/**
 * Gets display name for a tag node
 * @param {Object} tagNode - Tag node from tree
 * @returns {string} Display name
 */
export function getTagName(tagNode) {
  return tagNode.content.name || tagNode.name || tagNode.id;
}

/**
 * Gets color for a tag node
 * @param {Object} tagNode - Tag node from tree
 * @returns {string} Hex color code
 */
export function getTagColor(tagNode) {
  return tagNode.content.color || '#3b82f6';
}

export async function render(item, api) {
  const container = api.createElement('div', { style: 'padding: 15px;' }, []);

  // Header
  const header = api.createElement('h3', { style: 'margin-top: 0;' }, [
    item.name || 'Untitled Script'
  ]);
  container.appendChild(header);

  // Description
  if (item.content.description) {
    const desc = api.createElement('p', { style: 'color: #666; font-style: italic;' }, [
      item.content.description
    ]);
    container.appendChild(desc);
  }

  // Code display
  const code = api.createElement('pre', {
    style: `
      background: #f8f8f8;
      padding: 15px;
      border-radius: 4px;
      border: 1px solid #ddd;
      overflow-x: auto;
      font-family: 'SF Mono', Monaco, monospace;
      font-size: 13px;
      line-height: 1.5;
    `
  }, [item.content.code || '// No code']);
  container.appendChild(code);

  // Buttons
  const buttons = api.createElement('div', { 
    style: 'margin-top: 15px; display: flex; gap: 10px;' 
  }, []);

  const runBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px; font-weight: 500;',
    onclick: async () => {
      runBtn.disabled = true;
      runBtn.textContent = 'Running...';

      try {
        // Get the REPL API which has the helper functions
        const replApi = api.createREPLContext();

        // Execute the script code with REPL API
        const asyncFn = new Function('api', `
          return (async () => {
            ${item.content.code}
          })();
        `);

        const result = await asyncFn(replApi);
        alert('Script executed!\n\nResult: ' + (
          result !== undefined 
            ? JSON.stringify(result, null, 2) 
            : 'No return value'
        ));
      } catch (error) {
        alert('Error executing script:\n\n' + error.message);
      } finally {
        runBtn.disabled = false;
        runBtn.textContent = 'Run Script';
      }
    }
  }, ['Run Script']);
  buttons.appendChild(runBtn);

  const editBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      // Navigate to raw editor for this item
      api.editRaw(item.id);
    }
  }, ['Edit']);
  buttons.appendChild(editBtn);

  const copyBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      navigator.clipboard.writeText(item.content.code);
      copyBtn.textContent = 'Copied!';
      setTimeout(() => copyBtn.textContent = 'Copy Code', 1000);
    }
  }, ['Copy Code']);
  buttons.appendChild(copyBtn);

  container.appendChild(buttons);

  return container;
}

